import React, { useState, useEffect } from "react";
import { FooterSocialLinks } from "./navlinks";

const SocialLinksv2 = () => {
  const [activeSocialLinks, setActiveSocialLinks] = useState(false);
  const [currentUrl, setCurrentUrl] = useState("");

  useEffect(() => {
    if (typeof window !== "undefined") {
      setCurrentUrl(window.location.href);
    }
  }, []);

  const handleOpen = () => {
    setActiveSocialLinks(!activeSocialLinks);
  };

  const getHref = (link) => {
    if (link.id === 0) {
      const defaultMessage =
        "Hi there! I am looking for your Services, Shall we Start the discussion: ";
      const fullMessage = encodeURIComponent(`${defaultMessage}${currentUrl}`);
      return `https://wa.me/919500139200?text=${fullMessage}`;
    }
    return link.action;
  };

  return (
    <div className="landingReachOut">
      <div
        className={`landingReachOut__links gap-md ${
          activeSocialLinks ? "open" : ""
        }`}
      >
        <div className="landingReachOut-btn about-p-two" onClick={handleOpen}>
          Close
        </div>
        <div className={`landingReachOut__link gap-md`}>
          <span className="landingReachOut-span about-p-three">Reach us</span>
          {FooterSocialLinks.map((links) => (
            <div
              className="landingReachOut__links--wrapper item-center gap-4"
              key={links.id}
            >
              <a
                className="font-black"
                href={getHref(links)}
                target={links.id === 0 ? "_blank" : "_self"}
                rel="noopener noreferrer"
              >
                <img src={links.sidebarIcon} alt={links.title} />
              </a>
            </div>
          ))}
        </div>
      </div>

      <div
        className={`vertical-text about-p-two item-center ${
          activeSocialLinks ? "active" : ""
        }`}
        onClick={handleOpen}
      >
        Reach Out
      </div>
    </div>
  );
};

export default SocialLinksv2;
