import React, { useEffect, useState } from "react";
import { Accordion } from "react-bootstrap";
import AnimatedHeading from "./animatedText";
import { Navlinks } from "./navlinks";

import CompanyLogo from "@styles/assets/images/company_logo.svg";
import navdownarrow from "@styles/assets/images/nav-down-arrow.svg";
import iconbottom from "@styles/assets/images/header/icon-bottom.png";
import hamburger from "@styles/assets/images/header/list.svg";
import close from "@styles/assets/images/header/x-lg.svg";
import { Justtrylinks } from "./justtrylinks";
import { Link } from "gatsby";

/* ---------------------------------------------------------
   DEVICE DETECTION (SEO SAFE)
---------------------------------------------------------- */
const getIsMobile = () => {
  const smallScreen = typeof window !== "undefined" && window.innerWidth <= 991;
  return smallScreen;
};

/* ---------------------------------------------------------
   MAIN HEADER COMPONENT
---------------------------------------------------------- */
const LandingHeaderV2 = () => {
  const [isMobile, setIsMobile] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    const updateState = () => setIsMobile(getIsMobile());
    updateState();
    setMounted(true);
    window.addEventListener("resize", updateState);

    return () => window.removeEventListener("resize", updateState);
  }, []);

  /* ---------------------------------------------------------
     DESKTOP NAVIGATION
  ---------------------------------------------------------- */
  const DesktopNav = () => {
    const [activeMenu, setActiveMenu] = useState(null);
    const [activeClickItem, setActiveClickItem] = useState(null);
    const [activeDropdown, setActiveDropdown] = useState(null);

    const handleMouseEnter = (navlink) => {
      setActiveMenu(navlink.id);

      if (navlink.isDropdown) {
        setActiveDropdown(navlink.id);
      } else {
        setActiveDropdown(null);
      }

      if (navlink.clickitems?.length) {
        setActiveClickItem(navlink.clickitems[0]);
      } else {
        setActiveClickItem(null);
      }
    };

    const [openMenuId, setOpenMenuId] = useState(0);

    const toggleMenu = (id) => {
      setOpenMenuId(openMenuId === id ? null : id);
    };

    useEffect(() => {
      const handleClickOutside = (e) => {
        if (
          !e.target.closest(".mega-menu-v2") &&
          !e.target.closest(".header-li-v2") &&
          !e.target.closest(".submenu-wrapper")
        ) {
          setActiveMenu(null);
          setActiveDropdown(null);
          setActiveClickItem(null);
          setOpenMenuId(null);
        }
      };

      document.addEventListener("click", handleClickOutside);
      return () => document.removeEventListener("click", handleClickOutside);
    }, []);

    const trapScroll = (e) => {
      const el = e.currentTarget;

      const atTop = el.scrollTop === 0;
      const atBottom = el.scrollTop + el.clientHeight >= el.scrollHeight;

      if ((atTop && e.deltaY < 0) || (atBottom && e.deltaY > 0)) {
        e.preventDefault();
      }

      e.stopPropagation();
    };

    return (
      <div className="desktop-nav justify_between w-100">
        <Link to={Justtrylinks.Home} className="company-logo-v2">
          <img src={CompanyLogo} alt="Company logo" width={226} height={40} />
        </Link>

        <div className="header-links-v2 flex-center gap-sm">
          {Navlinks.map((navlink) => {
            const [activeClickItem, setActiveClickItem] = useState(
              navlink.clickitems?.[0],
            );

            return (
              <div
                key={navlink.id}
                onMouseEnter={() => handleMouseEnter(navlink)}
              >
                <ul>
                  <li className="flex-center header-li-v2">
                    <AnimatedHeading
                      text={navlink.title}
                      link={navlink.link}
                      // onClick={() => setActiveMenu((prev) => !prev)}
                      as="span"
                      className="about-p-two font-black header-link-v2 d-flex align-item-center"
                      hoverColor="#6b24ff"
                    />

                    {navlink.icon && (
                      <img
                        src={navdownarrow}
                        alt="header-arrow-icon"
                        className="header-v2-arrow-icon"
                      />
                    )}
                  </li>
                </ul>

                {navlink.isSubItems === true &&
                  navlink.icon === true &&
                  activeMenu === navlink.id && (
                    <div className="mega-menu-v2 flex-column">
                      <div className="c-grid grid-two">
                        <div className="mega-left-v2 item-start gap-sm">
                          {navlink.clickitems?.map((clickitem) => (
                            <div key={clickitem.id}>
                              <AnimatedHeading
                                key={clickitem.id}
                                text={clickitem.clickTitle}
                                as="span"
                                className={`about-p font-black header-link-v2 ${
                                  activeClickItem?.id === clickitem.id
                                    ? "active-title"
                                    : ""
                                }`}
                                hoverColor="#6b24ff"
                                onClick={() => setActiveClickItem(clickitem)}
                              />
                            </div>
                          ))}

                          <div className="clickitem-img">
                            <img
                              src={activeClickItem?.img}
                              alt={activeClickItem?.clickTitle}
                            />
                          </div>

                          {activeClickItem?.btnLink ? (
                            <Link
                              to={activeClickItem.btnLink}
                              className="header-btn about-p-two"
                            >
                              {activeClickItem.btnName}
                            </Link>
                          ) : activeClickItem?.linkItems?.length > 0 ? (
                            activeClickItem.linkItems[0].subMenus?.length >
                            0 ? (
                              <Link
                                to={
                                  activeClickItem.linkItems[0].subMenus[0]
                                    .subLink
                                }
                                className="header-btn about-p-two"
                              >
                                {activeClickItem.btnName}
                              </Link>
                            ) : (
                              <Link
                                to={activeClickItem.linkItems[0].link}
                                className="header-btn about-p-two"
                              >
                                {activeClickItem.btnName}
                              </Link>
                            )
                          ) : null}
                        </div>

                        <div className="mega-right-wrapper-v2 flex-between">
                          <div
                            className="mega-right-v2 flex-start gap-md"
                            onWheel={trapScroll}
                          >
                            <div className="link-items mega-right-v2-link">
                              {activeClickItem?.linkItems.map((link) => {
                                const hasSubmenu = !!link.subMenus;
                                const isOpen = openMenuId === link.id;

                                return (
                                  <div key={link.id}>
                                    <div
                                      onClick={() =>
                                        hasSubmenu && toggleMenu(link.id)
                                      }
                                      className={`${
                                        hasSubmenu ? "flex" : "flex-column"
                                      }`}
                                    >
                                      <AnimatedHeading
                                        text={link.linkName}
                                        as="span"
                                        className={`about-p-two font-black cursor-pointer ${
                                          hasSubmenu && isOpen
                                            ? "submenu-active-title"
                                            : ""
                                        }`}
                                        hoverColor="#6b24ff"
                                        link={
                                          !hasSubmenu ? link.link : undefined
                                        }
                                      />
                                    </div>
                                  </div>
                                );
                              })}
                            </div>

                            {openMenuId != null && (
                              <div className="submenu-wrapper flex-column">
                                {activeClickItem?.linkItems
                                  .find((item) => item.id === openMenuId)
                                  ?.subMenus?.map((sub) => (
                                    <AnimatedHeading
                                      key={sub.id}
                                      text={sub.subLinkName}
                                      link={sub.subLink}
                                      as="span"
                                      className="about-p-two font-normal submenu-item"
                                      hoverColor="#6b24ff"
                                    />
                                  ))}
                              </div>
                            )}
                          </div>

                          <div className="mega-menu-v2-r-bottom justify_between">
                            {[1, 2, 3, 4].map((i) => (
                              <p
                                key={i}
                                className="about-p-two font-white flex-center gap-2"
                              >
                                <img src={iconbottom} alt="icon-bottom" />
                                {navlink.bottomText}
                              </p>
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="mega-menu-v2-bottom item-center">
                        <p className="about-p-two">
                          Want to develop your digital product? Let’s connect!{" "}
                          <Link
                            className="mega-menu-v2-bottom-link"
                            to={Justtrylinks.contactUs}
                          >
                            Contact Us
                          </Link>
                        </p>
                      </div>
                    </div>
                  )}
                {navlink.isDropdown && activeDropdown === navlink.id && (
                  <div className="drop-menu-v2 flex-column">
                    {navlink.dropDownItems.map((drop) => (
                      <AnimatedHeading
                        key={drop.id}
                        text={drop.name}
                        link={drop.link}
                        linkClass="drop-menu-v2-links"
                        as="span"
                        className="about-p-two font-normal d-flex align-item-center w-full"
                        hoverColor="#6b24ff"
                      />
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <Link to={Justtrylinks.contactUs} className="header-btn about-p-two">
          Contact Us
        </Link>
      </div>
    );
  };

  /* ---------------------------------------------------------
     MOBILE NAVIGATION
  ---------------------------------------------------------- */
  const MobileNav = () => {
    const [toggleShow, setToggleShow] = useState(false);

    const handleToggleShow = () => {
      setToggleShow(!toggleShow);
    };

    return (
      <div className="tablet-nav justify_between w-100">
        <Link to={Justtrylinks.Home} className="company-logo-v2">
          <img src={CompanyLogo} alt="Company logo" width={226} height={40} />
        </Link>

        {toggleShow && (
          <div className="tablet-mega-menu">
            <div className="justify_between tablet-mega-menu-header">
              <img
                src={CompanyLogo}
                alt="Company logo"
                width={226}
                height={40}
                style={{
                  maxWidth: "100%",
                  height: "auto",
                }}
              />

              <img
                src={close}
                onClick={handleToggleShow}
                alt="Close menu"
                width={30}
              />
            </div>

            <div className="tablet-mega-menu-content">
              {/* Main Accordion for all expandable items */}
              <Accordion alwaysOpen={false}>
                {Navlinks.map((item, index) => {
                  // Items with clickitems (complex menu structure)
                  if (item.clickitems && item.clickitems.length > 0) {
                    return (
                      <Accordion.Item
                        key={item.id}
                        eventKey={`item-${item.id}`}
                      >
                        <Accordion.Header>
                          <div className="about-p">{item.title}</div>
                        </Accordion.Header>

                        <Accordion.Body>
                          {/* SECOND LEVEL */}
                          <Accordion alwaysOpen={false}>
                            {item.clickitems?.map((clickItem) => (
                              <Accordion.Item
                                key={clickItem.id}
                                eventKey={`level2-${item.id}-${clickItem.id}`}
                                className="mb-4"
                              >
                                <Accordion.Header>
                                  <div className="about-p">
                                    {clickItem.clickTitle}
                                  </div>
                                </Accordion.Header>

                                <Accordion.Body>
                                  <ul className="mb-4">
                                    {clickItem.linkItems.map((link) => (
                                      <li
                                        key={link.id}
                                        className="list-unstyled mb-2"
                                      >
                                        {/* THIRD LEVEL */}
                                        {link.subMenus?.length > 0 ? (
                                          <Accordion alwaysOpen={false}>
                                            <Accordion.Item
                                              eventKey={`level3-${item.id}-${clickItem.id}-${link.id}`}
                                            >
                                              <Accordion.Header>
                                                <div className="about-p-two">
                                                  {link.linkName}
                                                </div>
                                              </Accordion.Header>
                                              <Accordion.Body>
                                                <ul>
                                                  {link.subMenus.map((sub) => (
                                                    <li
                                                      key={sub.id}
                                                      className="list-unstyled mb-1"
                                                    >
                                                      <Link
                                                        className="about-p-two font-black"
                                                        to={sub.subLink}
                                                      >
                                                        {sub.subLinkName}
                                                      </Link>
                                                    </li>
                                                  ))}
                                                </ul>
                                              </Accordion.Body>
                                            </Accordion.Item>
                                          </Accordion>
                                        ) : (
                                          <Link
                                            className="about-p-two font-black"
                                            to={link.link}
                                          >
                                            {link.linkName}
                                          </Link>
                                        )}
                                      </li>
                                    ))}
                                  </ul>
                                  {clickItem.expertsOnly && (
                                    <Link
                                      to={clickItem.btnLink}
                                      className="header-btn about-p-two"
                                    >
                                      {clickItem.btnName}
                                    </Link>
                                  )}
                                </Accordion.Body>
                              </Accordion.Item>
                            ))}
                          </Accordion>
                        </Accordion.Body>
                      </Accordion.Item>
                    );
                  }

                  // Items with dropDownItems
                  if (item.isDropdown && item.dropDownItems?.length > 0) {
                    return (
                      <Accordion.Item
                        key={item.id}
                        eventKey={`dropdown-${item.id}`}
                      >
                        <Accordion.Header>
                          <div className="about-p">{item.title}</div>
                        </Accordion.Header>
                        <Accordion.Body>
                          <ul>
                            {item.dropDownItems.map((dropItem) => (
                              <li
                                key={dropItem.id}
                                className="list-unstyled mb-2"
                              >
                                <Link
                                  className="about-p-two font-black"
                                  to={dropItem.link}
                                >
                                  {dropItem.name}
                                </Link>
                              </li>
                            ))}
                          </ul>
                        </Accordion.Body>
                      </Accordion.Item>
                    );
                  }

                  return null;
                })}
              </Accordion>

              {/* Simple links outside accordion */}
              <div className="item-start">
                {Navlinks.filter(
                  (item) =>
                    (!item.clickitems || item.clickitems.length === 0) &&
                    !item.isDropdown,
                ).map((item) => (
                  <Link
                    key={item.id}
                    to={item.link}
                    className="about-p-two link-accordian font-black accordion-item w-100"
                  >
                    {item.title}
                  </Link>
                ))}
              </div>
            </div>
          </div>
        )}

        <img
          src={hamburger}
          onClick={handleToggleShow}
          alt="Hamburger menu"
          width={30}
        />
      </div>
    );
  };

  /* ---------------------------------------------------------
     FINAL RETURN (device-based rendering)
  ---------------------------------------------------------- */
  return (
    <header className="header-wrapper-v2">
      <nav className="header-inner-wrapper-v2 justify_between">
        {mounted ? (
          isMobile ? (
            <MobileNav />
          ) : (
            <DesktopNav />
          )
        ) : (
          // while mounting, render a minimal header (logo only) to avoid flicker
          <div className="desktop-nav justify_between w-100">
            <Link to={`${Justtrylinks.Home}`} className="company-logo-v2">
              <img
                src={CompanyLogo}
                alt="Company logo"
                width={226}
                height={40}
                style={{
                  maxWidth: "100%",
                  height: "auto",
                }}
              />
            </Link>
          </div>
        )}
      </nav>
    </header>
  );
};

export default LandingHeaderV2;
